CoordenadaGrid obter_coordenada_borda(char* str) {
    CoordenadaGrid coord = {15, 9}; // Padrão caso não encontre (vai retornar espaço)

    if (strcmp(str, "canto_sup_dir") == 0) coord.coluna = 11;
    else if (strcmp(str, "canto_sup_esq") == 0) coord.coluna = 9;
    else if (strcmp(str, "canto_inf_dir") == 0) coord.coluna = 14;
    else if (strcmp(str, "canto_inf_esq") == 0) coord.coluna = 13;
    else if (strcmp(str, "borda_horizontal") == 0) coord.coluna = 10;
    else if (strcmp(str, "borda_vertical") == 0) coord.coluna = 12;

    return coord;
}

// Função que converte um caractere ASCII para a sua posição (Coluna, Linha) na imagem
CoordenadaGrid obter_coordenada_caractere(char c) {
    CoordenadaGrid coord = {0, 4}; // Padrão caso não encontre (vai retornar espaço)

    // Letras Maiúsculas (A-P estão na Linha 0, Q-Z na Linha 1)
    if (c >= 'A' && c <= 'P') {
        coord.coluna = c - 'A';
        coord.linha = 0;
    }
    else if (c >= 'Q' && c <= 'Z') {
        coord.coluna = c - 'Q';
        coord.linha = 1;
    }
    // Letras Minúsculas (a-p estão na Linha 2, q-z na Linha 3)
    else if (c >= 'a' && c <= 'p') {
        coord.coluna = c - 'a';
        coord.linha = 2;
    }
    else if (c >= 'q' && c <= 'z') {
        coord.coluna = c - 'q';
        coord.linha = 3;
    }
    // Números (0-9 estão na Linha 8, começando na Coluna 6)
    else if (c >= '0' && c <= '9') {
        coord.coluna = 6 + (c - '0');
        coord.linha = 8;
    }
    // Símbolos especiais
    else if (c == ' ') {
        coord.coluna = 0;
        coord.linha = 4;
    }
    else if (c == '(') {
        coord.coluna = 10;
        coord.linha = 1;
    }
    else if (c == ')') {
        coord.coluna = 11;
        coord.linha = 1;
    }
    else if (c == ':') {
        coord.coluna = 12;
        coord.linha = 1;
    }
    else if (c == ';') {
        coord.coluna = 13;
        coord.linha = 1;
    }
    else if (c == '[') {
        coord.coluna = 14;
        coord.linha = 1;
    }
    else if (c == ']') {
        coord.coluna = 15;
        coord.linha = 1;
    }
    else if (c == '-') { 
        coord.coluna = 3;
        coord.linha = 6;
    }
    else if (c == '?') { 
        coord.coluna = 6;
        coord.linha = 6;
    }
    else if (c == '!') { 
        coord.coluna = 7;
        coord.linha = 6;
    }
    else if (c == '.') { 
        coord.coluna = 8;
        coord.linha = 6;
    }
    else if (c == '<') { 
        coord.coluna = 12;
        coord.linha = 6;
    }
    else if (c == '>') { 
        coord.coluna = 13;
        coord.linha = 6;
    }
    else if (c == '/') { 
        coord.coluna = 3;
        coord.linha = 7;
    }
    else if (c == ',') { 
        coord.coluna = 4;
        coord.linha = 7;
    }

    return coord;
}

// Desenha um único caractere de 8x8 na tela VGA (com fundo transparente)
void desenhar_caractere(int tela_x, int tela_y, char caractere) {
    
    // Se for o caractere de espaço, desenha o bloco 8x8 preenchido com 0xFF5F
    if (caractere == ' ') {
        for (int y = 0; y < 8; y++) {
            for (int x = 0; x < 8; x++) {
                // Desenha diretamente todos os pixels da matriz 'espaco' na tela
                write_pixel(tela_x + x, tela_y + y, espaco[y][x]);
            }
        }
        return; // Finaliza aqui para o espaço
    }

    // Código original para todos os outros caracteres normais:
    CoordenadaGrid coord = obter_coordenada_caractere(caractere);
    
    int img_start_x = (coord.coluna * 9); 
    int img_start_y = (coord.linha * 9); 

    for (int y = 0; y < 8; y++) {
        for (int x = 0; x < 8; x++) {
            unsigned short cor_pixel = imagem_data[img_start_y + y][img_start_x + x];
            
            // 0xFBE5 é o rosa de fundo da imagem original
            if (cor_pixel != 0xFBE5) {
                write_pixel(tela_x + x, tela_y + y, cor_pixel);
            }
        }
    }
}

// Função para desenhar um texto completo (String)
void desenhar_texto(int tela_x, int tela_y, const char *texto) {
    int i = 0;
    while (texto[i] != '\0') {
        // Desenha o caractere atual
        desenhar_caractere(tela_x + (i * 8), tela_y, texto[i]); // Avança 8 pixels por letra
        i++;
    }
}